"""Practical token counting and embedding similarity demo."""
import math

# ── pip install tiktoken openai ──────────────────────────────────

# ── 1. Token Counting ────────────────────────────────────────────
def count_tokens(text: str, model: str = "gpt-4o") -> int:
    """Count tokens for a text string using the model's tokenizer."""
    try:
        import tiktoken
        enc = tiktoken.encoding_for_model(model)
        return len(enc.encode(text))
    except ImportError:
        # Rough estimate if tiktoken not installed
        return len(text) // 4


def count_messages_tokens(messages: list[dict], model: str = "gpt-4o") -> int:
    """Count tokens for a full messages list (includes message overhead)."""
    try:
        import tiktoken
        enc = tiktoken.encoding_for_model(model)
        total = 0
        for msg in messages:
            total += 4  # per-message overhead: role + separators
            for key, value in msg.items():
                total += len(enc.encode(str(value)))
        total += 2  # reply primer
        return total
    except ImportError:
        return sum(len(str(m)) // 4 for m in messages)


# ── 2. Cosine Similarity (pure Python, no numpy needed) ──────────
def cosine_similarity(vec_a: list[float], vec_b: list[float]) -> float:
    """Compute cosine similarity between two embedding vectors."""
    dot = sum(a * b for a, b in zip(vec_a, vec_b))
    mag_a = math.sqrt(sum(x ** 2 for x in vec_a))
    mag_b = math.sqrt(sum(x ** 2 for x in vec_b))
    if mag_a == 0 or mag_b == 0:
        return 0.0
    return dot / (mag_a * mag_b)


# ── 3. Semantic Search (mock embeddings for demo) ────────────────
MOCK_EMBEDDINGS = {
    "Python is great for AI": [0.8, 0.6, 0.1, 0.2],
    "Machine learning with Python": [0.75, 0.65, 0.15, 0.18],
    "Stock market analysis": [0.1, 0.2, 0.9, 0.7],
    "Financial portfolio management": [0.05, 0.15, 0.85, 0.75],
    "Deep learning frameworks": [0.7, 0.7, 0.2, 0.1],
}

def semantic_search(query_embedding: list[float], top_k: int = 3) -> list[tuple]:
    """Return top_k most similar documents by cosine similarity."""
    scores = [
        (text, cosine_similarity(query_embedding, emb))
        for text, emb in MOCK_EMBEDDINGS.items()
    ]
    scores.sort(key=lambda x: -x[1])
    return scores[:top_k]


# ── 4. Context window budget tracker ────────────────────────────
class ContextBudget:
    def __init__(self, model: str = "gpt-4o", max_output: int = 2000):
        MODEL_LIMITS = {"gpt-4o": 128_000, "claude-sonnet-4-6": 200_000, "gemini-2.5-pro": 1_000_000}
        self.limit = MODEL_LIMITS.get(model, 128_000)
        self.max_output = max_output
        self.model = model

    def available_input_tokens(self, current_messages: list[dict]) -> int:
        used = count_messages_tokens(current_messages, self.model)
        return self.limit - used - self.max_output

    def will_fit(self, new_message: str, current_messages: list[dict]) -> bool:
        new_tokens = count_tokens(new_message, self.model)
        return new_tokens <= self.available_input_tokens(current_messages)


if __name__ == "__main__":
    # Demo 1: Token counting
    print("=== Token Counting ===")
    texts = ["Hello", "Hello, world!", "Unbelievable GPT-4o performance!"]
    for t in texts:
        print(f"  '{t}' → {count_tokens(t)} tokens")

    # Demo 2: Message overhead
    messages = [
        {"role": "system", "content": "You are a helpful assistant."},
        {"role": "user", "content": "What is machine learning?"},
    ]
    print(f"\n  Full messages list → {count_messages_tokens(messages)} tokens")

    # Demo 3: Semantic search
    print("\n=== Semantic Search ===")
    query_vec = [0.78, 0.62, 0.12, 0.19]  # mock "AI Python" query
    results = semantic_search(query_vec)
    for text, score in results:
        print(f"  {score:.3f} | {text}")

    # Demo 4: Budget check
    print("\n=== Context Budget ===")
    budget = ContextBudget("gpt-4o")
    available = budget.available_input_tokens(messages)
    print(f"  Available input tokens: {available:,}")
    print(f"  New message fits: {budget.will_fit('Tell me everything about neural networks.', messages)}")

