def most_similar_pair(texts: list[str], embeddings: list[list[float]]) -> tuple[str, str, float]:
    best_score = -1
    best_pair = (texts[0], texts[1])
    for i in range(len(texts)):
        for j in range(i + 1, len(texts)):
            score = cosine_similarity(embeddings[i], embeddings[j])
            if score > best_score:
                best_score = score
                best_pair = (texts[i], texts[j])
    return best_pair[0], best_pair[1], best_score
